import { useState, useEffect } from 'react';
import { Card, Form, Button, Typography, Toast, Tabs, TabPane, Divider, Spin } from '@douyinfe/semi-ui';
import { IconGridView, IconLink } from '@douyinfe/semi-icons';
import { useAuthStore } from '@/store/authStore';
import { isFeishuEnv, isFeishuConfigured, redirectToFeishuOAuth } from '@/lib/feishuAuth';

const { Title, Text } = Typography;

export default function LoginPage() {
  const { login, register, feishuAutoLogin } = useAuthStore();
  const [loading, setLoading] = useState(false);
  const [feishuLoading, setFeishuLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('login');
  const [autoLoginAttempted, setAutoLoginAttempted] = useState(false);

  const inFeishu = isFeishuEnv();
  const feishuReady = isFeishuConfigured();

  // Auto-login in Feishu environment
  useEffect(() => {
    if (autoLoginAttempted) return;
    setAutoLoginAttempted(true);

    if (feishuReady) {
      setFeishuLoading(true);
      feishuAutoLogin()
        .then((success) => {
          if (success) {
            Toast.success('飞书登录成功');
          }
        })
        .catch((err) => {
          console.error('飞书自动登录失败:', err);
          Toast.error(`飞书登录失败: ${err?.message || '未知错误'}`);
        })
        .finally(() => {
          setFeishuLoading(false);
        });
    }
  }, [feishuReady, autoLoginAttempted, feishuAutoLogin]);

  const handleLogin = async (values: any) => {
    setLoading(true);
    try {
      await login(values.email, values.password);
      Toast.success('登录成功');
    } catch (err: any) {
      Toast.error(err.message || '登录失败');
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (values: any) => {
    if (values.password !== values.confirmPassword) {
      Toast.error('两次密码不一致');
      return;
    }
    setLoading(true);
    try {
      await register(values.email, values.password, values.name, 'ENGINEER');
      Toast.success('注册成功');
    } catch (err: any) {
      Toast.error(err.message || '注册失败');
    } finally {
      setLoading(false);
    }
  };

  const handleFeishuLogin = async () => {
    if (!feishuReady) {
      Toast.warning('飞书应用未配置，请联系管理员');
      return;
    }

    if (inFeishu) {
      // In Feishu client: use in-app login
      setFeishuLoading(true);
      try {
        const success = await feishuAutoLogin();
        if (success) {
          Toast.success('飞书登录成功');
        } else {
          Toast.error('飞书登录失败，请重试');
        }
      } catch (err: any) {
        Toast.error(err.message || '飞书登录失败');
      } finally {
        setFeishuLoading(false);
      }
    } else {
      // In browser: redirect to Feishu OAuth
      redirectToFeishuOAuth();
    }
  };

  // Show a loading screen while auto-login is in progress
  if (feishuLoading && inFeishu) {
    return (
      <div
        style={{
          height: '100vh',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          background: 'var(--semi-color-bg-0)',
          gap: 16,
        }}
      >
        <Spin size="large" />
        <Text type="tertiary">正在通过飞书免登...</Text>
      </div>
    );
  }

  return (
    <div
      style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'var(--semi-color-bg-0)',
      }}
    >
      <Card
        style={{
          width: 400,
          boxShadow: 'var(--semi-shadow-elevated)',
        }}
      >
        <div style={{ textAlign: 'center', marginBottom: 24 }}>
          <IconGridView style={{ fontSize: 36, color: 'var(--semi-color-primary)' }} />
          <Title heading={3} style={{ margin: '8px 0 4px' }}>
            成本核算工作台
          </Title>
          <Text type="tertiary">高压线束成本动态模型</Text>
        </div>

        <Tabs activeKey={activeTab} onChange={setActiveTab}>
          <TabPane tab="登录" itemKey="login">
            <Form onSubmit={handleLogin} style={{ marginTop: 16 }}>
              <Form.Input
                field="email"
                label="邮箱"
                placeholder="admin@harness.dev"
                rules={[{ required: true, message: '请输入邮箱' }]}
              />
              <Form.Input
                field="password"
                label="密码"
                mode="password"
                placeholder="请输入密码"
                rules={[{ required: true, message: '请输入密码' }]}
              />
              <Button
                htmlType="submit"
                type="primary"
                theme="solid"
                block
                loading={loading}
                style={{ marginTop: 12 }}
              >
                登录
              </Button>
            </Form>
            <div style={{ marginTop: 16, textAlign: 'center' }}>
              <Text type="tertiary" size="small">
                默认账号: admin@harness.dev / admin123
              </Text>
              <Divider style={{ margin: '16px 0' }}>
                <Text type="tertiary" size="small">或</Text>
              </Divider>
              <Button
                icon={<IconLink />}
                block
                loading={feishuLoading}
                disabled={!feishuReady}
                onClick={handleFeishuLogin}
                style={{ marginBottom: 8 }}
              >
                {inFeishu ? '飞书免登' : '飞书授权登录'}
              </Button>
              {!feishuReady && (
                <Text type="tertiary" size="small">
                  需配置 VITE_FEISHU_APP_ID 环境变量
                </Text>
              )}
            </div>
          </TabPane>

          <TabPane tab="注册" itemKey="register">
            <Form onSubmit={handleRegister} style={{ marginTop: 16 }}>
              <Form.Input
                field="name"
                label="姓名"
                placeholder="请输入姓名"
                rules={[{ required: true, message: '请输入姓名' }]}
              />
              <Form.Input
                field="email"
                label="邮箱"
                placeholder="请输入邮箱"
                rules={[{ required: true, message: '请输入邮箱' }]}
              />
              <Form.Input
                field="password"
                label="密码"
                mode="password"
                placeholder="至少6位"
                rules={[{ required: true, message: '请输入密码' }]}
              />
              <Form.Input
                field="confirmPassword"
                label="确认密码"
                mode="password"
                placeholder="再次输入密码"
                rules={[{ required: true, message: '请确认密码' }]}
              />
              <Button
                htmlType="submit"
                type="primary"
                theme="solid"
                block
                loading={loading}
                style={{ marginTop: 12 }}
              >
                注册
              </Button>
            </Form>
          </TabPane>
        </Tabs>
      </Card>
    </div>
  );
}
