import { Typography } from '@douyinfe/semi-ui';
const { Title, Text } = Typography;

interface KpiCardProps {
  label: string;
  value: string | number;
  unit?: string;  // e.g., '%', 'kg', 'h'
  prefix?: string; // e.g., '¥'
}

export default function KpiCard({ label, value, unit, prefix }: KpiCardProps) {
  const displayValue = typeof value === 'number' 
    ? (prefix || '') + value.toFixed(2) + (unit || '')
    : (prefix || '') + value + (unit || '');
  
  return (
    <div className="kpi-card">
      <Text style={{ color: 'var(--semi-color-text-2)', fontSize: 12 }}>{label}</Text>
      <Title heading={3} style={{ color: 'var(--semi-color-primary)', margin: '8px 0 0' }}>
        {displayValue}
      </Title>
    </div>
  );
}
